def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            overflow = ratio - 1
            penalty = overflow ** 3 * 200
            priorities[i] = penalty
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for k in range(1, 21):
                term = ((-1)**k) * (ratio ** k) / (k + 0.5)
                score += term
            if ratio < 0.3:
                priorities[i] = score * np.sqrt(capacity)
            elif ratio < 0.7:
                exp_component = np.exp(-capacity / (item + 0.1))
                priorities[i] = score * exp_component + np.log(capacity - item + 1)
            else:
                penalties = 0
                for m in range(1, 4):
                    penalties += (capacity % m) * 0.1
                priorities[i] = score / (1 + penalties)
        if capacity > 3 * item:
            priorities[i] += np.sin(capacity / (item + 1)) * 0.7
        elif capacity > item:
            priorities[i] -= np.cos(capacity - item) * 0.3
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
